-- ============================================================
-- Car Inventory Schema (ระบบสต๊อกรถยนต์มือสอง)
-- ============================================================
SET NAMES utf8mb4;
SET time_zone = '+07:00';

CREATE TABLE IF NOT EXISTS branches (
  id        INT AUTO_INCREMENT PRIMARY KEY,
  name      VARCHAR(100) NOT NULL,
  province  VARCHAR(100) NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE IF NOT EXISTS dealers (
  id        INT AUTO_INCREMENT PRIMARY KEY,
  name      VARCHAR(100) NOT NULL,
  phone     VARCHAR(30)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE IF NOT EXISTS brands (
  id        INT AUTO_INCREMENT PRIMARY KEY,
  name      VARCHAR(60) NOT NULL UNIQUE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE IF NOT EXISTS car_types (
  id          INT AUTO_INCREMENT PRIMARY KEY,
  value       VARCHAR(30) NOT NULL UNIQUE,
  label       VARCHAR(60) NOT NULL,
  sort_order  INT NOT NULL DEFAULT 0
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE IF NOT EXISTS users (
  id            INT AUTO_INCREMENT PRIMARY KEY,
  username      VARCHAR(50) NOT NULL UNIQUE,
  password_hash VARCHAR(255) NOT NULL,
  name          VARCHAR(100),
  role          VARCHAR(20) NOT NULL DEFAULT 'admin',
  created_at    TIMESTAMP DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE IF NOT EXISTS settings (
  setting_key   VARCHAR(50) PRIMARY KEY,
  setting_value TEXT NOT NULL,
  updated_at    TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE IF NOT EXISTS cars (
  id                INT AUTO_INCREMENT PRIMARY KEY,
  brand             VARCHAR(50)  NOT NULL,
  model             VARCHAR(80)  NOT NULL,
  car_type          VARCHAR(30)  NOT NULL,
  model_year        INT          NOT NULL,
  price             DECIMAL(12,2) NOT NULL,
  transmission      ENUM('auto','manual') NOT NULL,
  drivetrain        ENUM('2wd','4wd') NOT NULL DEFAULT '2wd',
  fuel_type         ENUM('gasoline','diesel','hybrid','ev') NOT NULL DEFAULT 'gasoline',
  mileage           INT          NOT NULL DEFAULT 0,
  color             VARCHAR(40),
  color_code        VARCHAR(20),
  license_plate     VARCHAR(20)  NOT NULL,
  status            ENUM('available','incoming','reserved','sold') NOT NULL DEFAULT 'available',
  featured          TINYINT(1)   NOT NULL DEFAULT 0,
  engine            VARCHAR(60),
  seats             INT,
  doors             INT,
  purchase_date     DATE         NOT NULL,
  registration_date DATE,
  branch_id         INT          NOT NULL,
  dealer_id         INT          NOT NULL,
  description       TEXT,
  equipment         JSON,
  images            JSON,
  created_at        TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  CONSTRAINT fk_branch FOREIGN KEY (branch_id) REFERENCES branches(id),
  CONSTRAINT fk_dealer FOREIGN KEY (dealer_id) REFERENCES dealers(id),
  INDEX idx_brand (brand),
  INDEX idx_type (car_type),
  INDEX idx_status (status),
  INDEX idx_price (price),
  INDEX idx_featured (featured),
  INDEX idx_plate (license_plate)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

